3	// Seeded suite + checks (backend/scripts/demo_data.py) read through the real API,
4	// then a full browser authoring round-trip (create → verify → delete) that
5	// mirrors the httpx API smoke but through the React UI a user actually drives.
6	test.describe('Suites page', () => {
7	  test.beforeEach(async ({ page }) => {
8	    await page.goto('/suites');
9	    await expect(page.getByRole('heading', { name: 'Suites', level: 3 })).toBeVisible();
10	  });
11	
