14	
15	    // Selection is the route now — the URL carries the suite id (deep-linkable).
16	    await expect(page).toHaveURL(/\/suites\/[0-9a-f-]+$/);
17	    // Detail panel renders the suite title (h4) and its seeded checks.
18	    await expect(page.getByRole('heading', { name: 'Orders quality', level: 4 })).toBeVisible();
19	    await expect(page.getByText('order_id not null')).toBeVisible();
