1	import { expect, test } from '@playwright/test';
2	
3	// NotificationsPanel on the seeded suite's detail page: per-suite alerting
4	// config (W6 — fronts notification_service). Sets a deterministic state
5	// (enabled + warn threshold), saves, and proves it survives a reload. The
6	// Teams webhook stays untouched — it's write-only (the API never returns it)
7	// and writing one would push a secret into the store; the spec only asserts
8	// the write-only affordance renders.
9	test.describe('Suite notifications panel', () => {
10	  const card = (page: import('@playwright/test').Page) =>
11	    page.locator('.ant-card').filter({ hasText: 'run outcomes to Microsoft Teams' });
12	
13	  const openSuite = async (page: import('@playwright/test').Page) => {
14	    await page.goto('/suites');
15	    await page.getByText('Orders quality').click();
16	    await expect(page).toHaveURL(/\/suites\/[0-9a-f-]+$/);
17	    await expect(card(page).getByText('Notifications', { exact: true })).toBeVisible();
18	  };
19	
20	  test('configure threshold routing and persist it across a reload', async ({ page }) => {
21	    await openSuite(page);
22	    const panel = card(page);
23	
24	    // Snapshot the config so the spec doesn't permanently mutate the seeded
25	    // suite (alerting behavior for every later dev-stack run); restored below.
26	    const suiteId = page.url().match(/suites\/([0-9a-f-]+)/)?.[1];
27	    const before = await (await page.request.get(`/api/v1/suites/${suiteId}/notifications`)).json();
28	
29	    // Deterministic target state: enabled + "On warn and worse".
30	    const enable = panel.getByRole('switch', { name: 'Enable notifications' });
31	    if (!(await enable.isChecked())) {
32	      await enable.click();
33	    }
34	    // Keyboard-only selection: rc-virtual-list parks option nodes in an
35	    // off-viewport measurement container, so clicking an option by role is
36	    // flaky (element "outside of the viewport"). On open the highlight sits
37	    // on the CURRENT value, so compute the arrow-key delta to the target.
38	    const OPTIONS = ['On fail / critical', 'On warn and worse', 'Always (every run)'];
39	    const target = OPTIONS.indexOf('On warn and worse');
40	    // The select renders its current value as visible text in the panel;
41	    // default (no config yet) is the first option.
42	    let current = 0;
43	    for (let i = 0; i < OPTIONS.length; i++) {
44	      if ((await panel.getByText(OPTIONS[i], { exact: true }).count()) > 0) {
45	        current = i;
46	        break;
47	      }
48	    }
49	
50	    const threshold = panel.getByRole('combobox');
51	    await threshold.click();
52	    await expect(page.locator('.ant-select-dropdown').last()).toBeVisible();
53	    for (let i = 0; i < Math.abs(target - current); i++) {
54	      await threshold.press(target > current ? 'ArrowDown' : 'ArrowUp');
55	    }
56	    await threshold.press('Enter');
57	
58	    await panel.getByRole('button', { name: 'Save' }).click();
59	    await expect(page.getByText('Notifications saved')).toBeVisible();
60	
61	    // Reload → the form re-seeds from the API with the saved values.
62	    await page.reload();
63	    await expect(card(page).getByText('On warn and worse')).toBeVisible();
64	    await expect(card(page).getByRole('switch', { name: 'Enable notifications' })).toBeChecked();
65	
66	    // Restore the pre-test config (webhook omitted = unchanged).
67	    const restored = await page.request.put(`/api/v1/suites/${suiteId}/notifications`, {
68	      data: { enabled: before.enabled, alert_on: before.alert_on },
69	    });
70	    expect(restored.ok()).toBe(true);
71	  });
72	
73	  test('webhook is a write-only secret affordance', async ({ page }) => {
74	    await openSuite(page);
75	    const panel = card(page);
76	
77	    // The field never echoes a stored URL — just a set/not-set tag + password
78	    // input. (Writing one is out of scope: it lands a secret in the store.)
79	    // Neither the seed nor any spec writes a webhook, so the tag is
80	    // deterministically 'not set' — pin it so a has_webhook regression fails.
81	    await expect(panel.getByText('Teams webhook')).toBeVisible();
82	    await expect(panel.getByLabel('Teams webhook URL')).toBeVisible();
83	    await expect(panel.getByText('not set', { exact: true })).toBeVisible();
84	  });
85	});

