1	import { DeleteOutlined } from '@ant-design/icons';
2	import {
3	  App,
4	  Alert,
5	  Button,
6	  Card,
7	  Empty,
8	  Flex,
9	  Input,
10	  Select,
11	  Spin,
12	  Switch,
13	  Tag,
14	  Typography,
15	} from 'antd';
16	import SimpleList from '../SimpleList';
17	import { useState } from 'react';
18	
19	import { CONNECTION_ENVS, type ConnectionEnv, ENV_COLORS, envLabel } from '../../api/connections';
20	import {
21	  createTriggerBinding,
22	  deleteTriggerBinding,
23	  listTriggerBindings,
24	  ORCHESTRATION_PROVIDERS,
25	  type OrchestrationProvider,
26	  PROVIDER_LABELS,
27	  setTriggerBindingEnabled,
28	  type TriggerBinding,
29	} from '../../api/triggerBindings';
30	import { useAsyncData } from '../../hooks/useAsyncData';
31	
32	/**
33	 * Suite-detail panel for the suite's run triggers: bind an orchestrator pipeline/
34	 * DAG so the suite runs on that pipeline's *success* (CLAUDE.md §4 — orchestration
35	 * providers are never a datasource; this is the one place a pipeline id meets a
36	 * suite). Anyone with `view` sees the bindings; `edit`+ (`canManage`) gets the
37	 * add / enable-toggle / remove controls, matching the backend gate.
38	 */
39	export function TriggersPanel({ suiteId, canManage }: { suiteId: string; canManage: boolean }) {
40	  const { state, reload } = useAsyncData(() => listTriggerBindings(suiteId));
41	
42	  return (
43	    <Card
44	      size="small"
45	      title={
46	        <Flex vertical gap={2}>
47	          <Typography.Text strong>Triggers</Typography.Text>
48	          <Typography.Text type="secondary" style={{ fontSize: 12, fontWeight: 400 }}>
49	            Run this suite when an orchestrator pipeline / DAG completes successfully.
50	          </Typography.Text>
51	        </Flex>
52	      }
53	    >
54	      <TriggersBody state={state} suiteId={suiteId} canManage={canManage} onChanged={reload} />
55	    </Card>
56	  );
57	}
58	
59	function TriggersBody({
60	  state,
61	  suiteId,
62	  canManage,
63	  onChanged,
64	}: {
65	  state: ReturnType<typeof useAsyncData<TriggerBinding[]>>['state'];
66	  suiteId: string;
67	  canManage: boolean;
68	  onChanged: () => void;
69	}) {
70	  if (state.status === 'loading') {
71	    return <Spin description="Loading triggers…" />;
72	  }
73	  if (state.status === 'error') {
74	    return (
75	      <Alert type="error" showIcon title="Failed to load triggers" description={state.error} />
76	    );
77	  }
78	  const bindings = state.data;
79	
80	  return (
81	    <Flex vertical gap={16}>
82	      {canManage && <AddTrigger suiteId={suiteId} onAdded={onChanged} />}
83	      {bindings.length === 0 ? (
84	        <Empty
85	          image={Empty.PRESENTED_IMAGE_SIMPLE}
86	          description="No triggers — this suite runs only on manual / scheduled runs."
87	        />
88	      ) : (
89	        <SimpleList
90	          dataSource={bindings}
91	          renderItem={(binding) => (
92	            <TriggerRow
93	              key={binding.id}
94	              binding={binding}
95	              canManage={canManage}
96	              onChanged={onChanged}
97	            />
98	          )}
99	        />
100	      )}
101	    </Flex>
102	  );
103	}
104	
105	function TriggerRow({
106	  binding,
107	  canManage,
108	  onChanged,
109	}: {
110	  binding: TriggerBinding;
111	  canManage: boolean;
112	  onChanged: () => void;
113	}) {
114	  const { message } = App.useApp();
115	  const [busy, setBusy] = useState(false);
116	
117	  const onToggle = async (enabled: boolean) => {
118	    setBusy(true);
119	    try {
120	      await setTriggerBindingEnabled(binding.id, enabled);
121	      message.success(`${binding.pipeline_or_dag_id}: ${enabled ? 'enabled' : 'disabled'}`);
122	      onChanged();
123	    } catch (err) {
124	      message.error(`Update failed: ${err instanceof Error ? err.message : 'unknown error'}`);
125	    } finally {
126	      setBusy(false);
127	    }
128	  };
129	
130	  const onRemove = async () => {
131	    setBusy(true);
132	    try {
133	      await deleteTriggerBinding(binding.id);
134	      message.success(`${binding.pipeline_or_dag_id}: removed`);
135	      onChanged();
136	    } catch (err) {
137	      message.error(`Remove failed: ${err instanceof Error ? err.message : 'unknown error'}`);
138	    } finally {
139	      setBusy(false);
140	    }
141	  };
142	
143	  return (
144	    <SimpleList.Item
145	      actions={
146	        canManage
147	          ? [
148	              <Switch
149	                key="toggle"
150	                size="small"
151	                checked={binding.enabled}
152	                loading={busy}
153	                onChange={onToggle}
154	                aria-label={`Enable ${binding.pipeline_or_dag_id}`}
155	              />,
156	              <Button
157	                key="remove"
158	                size="small"
159	                type="text"
160	                danger
161	                icon={<DeleteOutlined />}
162	                loading={busy}
163	                onClick={onRemove}
164	                aria-label={`Remove ${binding.pipeline_or_dag_id}`}
165	              />,
166	            ]
167	          : [<Tag key="state">{binding.enabled ? 'enabled' : 'disabled'}</Tag>]
168	      }
169	    >
170	      <Flex gap={10} align="center" style={{ minWidth: 0 }}>
171	        <Tag color={ENV_COLORS[binding.env as ConnectionEnv]}>
172	          {envLabel(binding.env as ConnectionEnv)}
173	        </Tag>
174	        <Flex vertical gap={2} style={{ minWidth: 0 }}>
175	          <Typography.Text code ellipsis>
176	            {binding.pipeline_or_dag_id}
177	          </Typography.Text>
178	          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
179	            {PROVIDER_LABELS[binding.provider]}
180	          </Typography.Text>
181	        </Flex>
182	      </Flex>
183	    </SimpleList.Item>
184	  );
185	}
186	
187	function AddTrigger({ suiteId, onAdded }: { suiteId: string; onAdded: () => void }) {
188	  const { message } = App.useApp();
189	  const [provider, setProvider] = useState<OrchestrationProvider>();
190	  const [env, setEnv] = useState<ConnectionEnv>();
191	  const [pipelineId, setPipelineId] = useState('');
192	  const [adding, setAdding] = useState(false);
193	
194	  const onAdd = async () => {
195	    const id = pipelineId.trim();
196	    if (!provider || !env || !id) return;
197	    setAdding(true);
198	    try {
199	      await createTriggerBinding({ provider, env, pipeline_or_dag_id: id, suite_id: suiteId });
200	      message.success(`${id}: trigger added`);
201	      setProvider(undefined);
202	      setEnv(undefined);
203	      setPipelineId('');
204	      onAdded();
205	    } catch (err) {
206	      message.error(`Add failed: ${err instanceof Error ? err.message : 'unknown error'}`);
207	    } finally {
208	      setAdding(false);
209	    }
210	  };
211	
212	  return (
213	    <Flex gap={8} align="center" wrap>
214	      <Select
215	        value={provider}
216	        onChange={setProvider}
217	        placeholder="Provider"
218	        style={{ width: 170 }}
219	        options={ORCHESTRATION_PROVIDERS.map((p) => ({ value: p, label: PROVIDER_LABELS[p] }))}
220	      />
221	      <Input
222	        value={pipelineId}
223	        onChange={(e) => setPipelineId(e.target.value)}
224	        placeholder="Pipeline / DAG id"
225	        style={{ flex: 1, minWidth: 160 }}
226	        onPressEnter={onAdd}
227	      />
228	      <Select
229	        value={env}
230	        onChange={setEnv}
231	        placeholder="Env"
232	        style={{ width: 100 }}
233	        options={CONNECTION_ENVS.map((e) => ({ value: e, label: envLabel(e) }))}
234	      />
235	      <Button
236	        type="primary"
237	        loading={adding}
238	        disabled={!provider || !env || !pipelineId.trim()}
239	        onClick={onAdd}
240	      >
241	        Add
242	      </Button>
243	    </Flex>
244	  );
245	}

